const order = $input.first().json;
const cust = order.customer || {};
const ship = order.shipping_address || order.billing_address || {};
const clientName = [cust.first_name, cust.last_name].filter(Boolean).join(' ').trim() || ship.name || null;
const clientPhone = (cust.phone || ship.phone || order.phone || '').replace(/\s+/g,'') || null;
const clientCity = ship.city || null;

const financial = (order.financial_status || '').toLowerCase();
const fulfillment = (order.fulfillment_status || '').toLowerCase();
let status = null;
if (fulfillment === 'fulfilled') status = 'entregado';
else if (['refunded','voided'].includes(financial)) status = 'cancelado';
else if (['paid','authorized','pending'].includes(financial)) status = 'confirmado';

const shopifyOrderId = String(order.id);
const totalUsd = parseFloat(order.total_price || 0);
const deliveryAddress = [ship.address1, ship.address2, ship.city, ship.province].filter(Boolean).join(', ') || null;

const patch = {};
if (clientName) patch.client_name = clientName;
if (clientPhone) patch.client_phone = clientPhone;
if (clientCity) patch.client_city = clientCity;
if (deliveryAddress) patch.delivery_address = deliveryAddress;
if (totalUsd) patch.total_usd = totalUsd;
if (status) patch.status = status;

const hasUpdates = Object.keys(patch).length > 0;
return [{ json: { shopifyOrderId, patch, hasUpdates, orderNumber: order.order_number || order.name } }];

